scwin.f_setMethAmt = function (){

};

scwin.btn_save_onclick = function (e) {
    scwin.f_Save();
};

scwin.btn_delete_onclick = function (e) {
    scwin.f_Delete();
};

scwin.sbm_RetrieveTaxInvoice_submitdone = async function (e) {
    if (ds_sellingEvidence.getRowCount() > 0 && ds_sellingEvidence.getCellData(0, "slipNo") !=""){
		$c.gus.cfEnableBtnOnly([btn_delete]);
		$c.gus.cfDisableBtnOnly([btn_save]);
		scwin.saveflag = "E";
	}else{
		$c.gus.cfEnableBtnOnly([btn_save]);
		$c.gus.cfDisableBtnOnly([btn_delete]);
		scwin.saveflag = "N";
	}	
    // ds_sellingEvidence event=OnLoadCompleted(rowcnt)>
    var rowcnt = ds_sellingEvidence.getRowCount();
    if (!(rowcnt > 0)){
		await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
		return;
	}else{
		await scwin.f_setsellingEvidence();
		if (ds_sellingEvidence.getCellData(0, "slipNo") != null && ds_sellingEvidence.getCellData(0, "slipNo") != ""){
			ica_spplyDt.setReadOnly(true);
			ica_slipDt.setReadOnly(true);
			$c.gus.cfEnableObj(ed_summary, false);
		}else{
		//	ed_summary.setValue( = scwin.p_summary;
			ica_spplyDt.setReadOnly(false);
			ica_slipDt.setReadOnly(false);
			$c.gus.cfEnableObj(ed_summary, true);
		}
	}
};

scwin.sbm_createDnTaxInvoice_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Msg == "FAIL"){

    } else {
        if (ds_sellingEvidence.getRowCount() > 0){
            $c.gus.cfEnableBtnOnly([btn_delete]);
            $c.gus.cfDisableBtnOnly([btn_save]);
            await $c.gus.cfAlertMsg(MSG_CM_INF_001);
            scwin.saveflag = "C";
            scwin.f_OnUnload();

        }
    }
};

scwin.sbm_deleteDnTaxInvoice_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Msg == "FAIL"){

    } else {
        await $c.gus.cfAlertMsg(MSG_CM_INF_004);	
        scwin.saveflag = "D";
        scwin.f_OnUnload();

    }
};

scwin.btn_close_onclick = function (e) {
    $c.win.closePopup();
};
